import{_ as r,c as t,o as b,a as _}from"./app.015fbf38.js";const m='{"title":"\u4F46\u4EE5\u7406\u66F8\u7B2C\u56DB\u7AE0","description":"","frontmatter":{"title":"\u4F46\u4EE5\u7406\u66F8\u7B2C\u56DB\u7AE0","date":"2018-06-11T13:20:56.000Z","categories":["\u8B80\u7D93\u7D00\u9304"]},"headers":[],"relativePath":"Bike/BikeTravel/20180611_\u4F46\u4EE5\u7406\u66F8\u7B2C\u56DB\u7AE0.md","lastUpdated":1648513476165}',e={},p=_('<p><img src="https://farm2.staticflickr.com/1823/42950257832_a3945ce388_h.jpg" alt=""><br> \u672C\u7AE0\u767B\u5834\u7684\u4E3B\u89D2\u662F\u5C3C\u5E03\u7532\u5C3C\u6492\u738B\uFF0C\u63CF\u8FF0\u7684\u4FE1\u4EF0\u7D93\u6B77<br> \u63A1\u7528\u5012\u6558\uFF0C\u662F\u5C3C\u5E03\u7532\u5C3C\u6492\u738B\u7684\u4E00\u9023\u4E32\u7D93\u6B77\u5F8C\uFF0C\u5FC3\u8072\u5BEB\u7167<br></p><p>\u63CF\u8FF0\u4E86\u738B\u505A\u4E86\u5922\uFF0C\u4F5C\u5922\u7684\u5922\u5883\u53EA\u6709\u4F46\u4EE5\u7406\u80FD\u89E3\u51FA\u4F86<br> \u672C\u7AE0\u89E3\u5922\u7684\u904E\u7A0B\u8207\u524D\u5E7E\u7AE0\u4E0D\u540C\u7684\u662F\uFF0C\u4F46\u4EE5\u7406\u80FD\u76F4\u63A5\u89E3\u5922<br> \u7B2C\u4E8C\u7AE0\u4E2D\u770B\u5230\u4F46\u4EE5\u7406\u5148\u7B54\u61C9\u4E86\u738B\uFF0C\u5F8C\u4F86\u56DE\u53BB\u5411\u795E\u79B1\u544A<br> \u795E\u5728\u591C\u9593\u624D\u8CDC\u4E0B\u555F\u793A\uFF0C\u4F46\u4EE5\u7406\u9818\u53D7\u4E86\uFF0C\u5922\u624D\u5F97\u4EE5\u89E3\u958B<br> \u672C\u7AE0\u5922\u5883\u4E2D\u6307\u793A\uFF0C\u738B\u8981\u53D7\u4E03\u500B\u6642\u671F\u7684\u82E6\uFF0C\u5982\u540C\u7272\u755C\u4E00\u6A23</p><p>\u53EF\u80FD\u5922\u5883\u4E2D\u6240\u5BA3\u544A\u7684\u5BE9\u5224\u90FD\u672A\u81E8\u5230\uFF0C\u6240\u4EE5\u738B\u9B06\u61C8\u4E86<br> \u7D93\u904E\u4E86\u4E00\u6BB5\u6642\u9593(\u53EF\u80FD12\u500B\u6708)\uFF0C\u738B\u7F79\u60A3\u4E86\u7CBE\u795E\u75C5\u75C7<br> \u884C\u70BA\u8209\u6B62\u985E\u4F3C\u7272\u755C\u4E00\u6A23(\u53EF\u80FD\u662F\u72C2\u72FC\u75C7)\uFF0C\u5403\u8349\u5982\u725B<br> \u76F4\u5230\u738B\u958B\u59CB\u8B19\u5351\uFF0C\u9858\u610F\u5BA3\u544A\u795E\u7684\u5049\u5927\uFF0C\u624D\u5F97\u4EE5\u6062\u5FA9\u6B63\u5E38</p><p>\u672C\u7AE0\u6BD4\u8F03\u7279\u5225\u7684\u9EDE\u5982\u4E0B\uFF1A</p><ol><li><p>\u5C3C\u5E03\u7532\u5C3C\u6492\u738B\u662F\u900F\u904E\u66C9\u8AED\uFF0C\u6B63\u5F0F\u8A54\u544A\u3001\u8B9A\u7F8E\u4EE5\u8272\u5217\u795E<br> \u5C3C\u5E03\u7532\u5C3C\u6492\u738B\u6B63\u5F0F\u5411\u5168\u570B\u4EBA\u6C11\u5BA3\u544A\u795E\u7684\u771F\u5BE6<br> \u524D\u5E7E\u7AE0\u770B\u5230\u5C3C\u5E03\u7532\u5C3C\u6492\u738B\u4EE5\u81EA\u6211\u70BA\u4E2D\u5FC3\u7684\u4EBA<br> \u53EA\u8981\u56DE\u7B54\u4E0D\u7B26\u4ED6\u7684\u671F\u5F85\uFF0C\u4FBF\u5F15\u4F86\u6BBA\u8EAB\u4E4B\u798D<br> \u53EF\u4EE5\u770B\u51FA\u4E00\u9023\u4E32\u7684\u7D93\u6B77\uFF0C\u8B93\u4ED6\u5351\u5FAE\u4E0B\u4F86</p></li><li><p>\u738B\u7684\u5922\u5883\u9019\u6B21\u6709\u8AAA\u51FA\u4F86\uFF0C\u4F46\u7121\u4EBA\u80FD\u89E3<br> \u738B\u7684\u5922\u5883\u9019\u6B21\u4E0D\u50CF\u5148\u524D\u5B8C\u5168\u8A18\u4E0D\u5F97\uFF0C\u4F46\u4E5F\u96E3\u89E3<br> \u6709\u53EF\u80FD\u8853\u58EB\u64D4\u5FC3\uFF0C\u8AAA\u932F\u8A71\u8B93\u738B\u4E0D\u6085\u4E0B\u5834\u5F88\u6158<br> \u6240\u4EE5\u9019\u908A\u6C92\u4EBA\u6562\u767C\u8072\uFF0C\u6562\u7AD9\u51FA\u4F86\u70BA\u738B\u89E3\u5922<br> \u738B\u5E38\u5E38\u4E1F\u51FA\u96E3\u984C\uFF0C\u8003\u9A57\u9019\u4E9B\u570B\u4E2D\u8F03\u70BA\u8070\u660E\u4EBA\u58EB<br> \u60F3\u60F3\u8981\u5728\u9019\u7A2E\u74B0\u5883\u4E2D\u751F\u5B58\uFF0C\u4F3C\u4E4E\u662F\u883B\u75DB\u82E6\u7684</p></li><li><p>\u4F46\u4EE5\u7406\u807D\u5B8C\u738B\u8AAA\u51FA\u5922\u5883\u6642\uFF0C\u9A5A\u8A1D\u7247\u6642\uFF0C\u5FC3\u610F\u9A5A\u60F6(V19)<br> \u4E0D\u78BA\u5B9A\u9019\u88E1\u4F46\u4EE5\u7406\u662F\u56E0\u70BA\u4EC0\u9EBC\u6709\u6B64\u53CD\u61C9<br> \u64D4\u6182\u738B\u7684\u8655\u5883\uFF0C\u53EF\u80FD\u63A5\u4E0B\u4F86\u8981\u63A5\u53D7\u5BE9\u5224?<br> \u9084\u662F\u6015\u89E3\u5922\u6642\uFF0C\u8B1B\u932F\u8A71\u6703\u60F9\u4F86\u6BBA\u982D\u4E4B\u7F6A?<br><br> \u4E0D\u904E\u9019\u908A\u6709\u53EF\u80FD\u4F46\u4EE5\u7406\u9810\u8A00\u5373\u5C07\u544A\u77E5\u738B\u7684\u4E0B\u5834<br> \u4F46\u4EE5\u7406\u70BA\u738B\u4E4B\u5F8C\u5373\u5C07\u767C\u751F\u7684\u4E8B\u611F\u5230\u9707\u9A5A\u3001\u60CB\u60DC<br> \u7AD9\u5728\u597D\u53CB\u7684\u7ACB\u5834\uFF0C\u4E5F\u6190\u60DC\u5C3C\u5E03\u7532\u5C3C\u6492\u738B\u7684\u8655\u5883<br> (\u53EF\u80FD\u738B\u8207\u4F46\u4EE5\u7406\u7684\u95DC\u4FC2\u4E0D\u932F\uFF0C\u4EE5\u670B\u53CB\u770B\u5F85)<br> \u800C\u738B\u4E5F\u544A\u8A34\u4ED6\uFF0C\u4E0D\u8981\u56E0\u5922\u548C\u5922\u7684\u8B1B\u89E3\u9A5A\u60F6(V19)<br> \u738B\u4E0D\u50CF\u524D\u5E7E\u7AE0\uFF0C\u60F1\u7F9E\u6210\u6012\u4E0B\u4EE4\u6BBA\u5BB3\u8853\u58EB</p></li><li><p>\u738B\u672A\u8B39\u614E\u8A00\u884C\uFF0C\u6700\u5F8C\u5922\u5883\u7684\u9810\u8A00\u6210\u771F\uFF0C\u6D41\u843D\u8352\u91CE<br> \u738B\u807D\u5B8C\u9810\u8A00\u5F8C\uFF0C\u525B\u958B\u59CB\u53EF\u80FD\u6703\u8B39\u614E\u6CE8\u610F\u8A00\u884C<br> \u4F46\u904E\u4E00\u6BB5\u6642\u9593\u90FD\u672A\u767C\u751F\u4EFB\u4F55\u4E8B\u60C5\u5C31\u9B06\u61C8\u4E86<br> \u7D93\u904E12\u500B\u6708\uFF0C\u7576\u738B\u8A87\u8B9A\u81EA\u5DF1\u7684\u6B0A\u529B\u3001\u80FD\u529B\u6642<br> \u9810\u8A00\u99AC\u4E0A\u514C\u73FE\uFF0C\u795E\u632A\u53BB\u5C3C\u5E03\u7532\u5C3C\u6492\u738B\u7684\u738B\u4F4D<br> \u738B\u53EF\u80FD\u7F79\u60A3&quot;\u72C2\u72FC\u75C7&quot;(\u4E00\u7A2E\u7CBE\u795E\u75C5\uFF0C\u5E7B\u60F3\u662F\u91CE\u7378)<br> \u7D93\u904E\u4E00\u6BB5\u6642\u9593(\u4E03\u671F)\uFF0C\u738B\u624D\u8B19\u5351\u7A31\u980C\u795E\u7684\u540D</p></li></ol><p>\u9A55\u50B2\u7684\u5FC3\uFF0C\u4F7F\u6211\u5011\u9060\u96E2\u4E0A\u5E1D\u3002\u8B19\u5351\u7684\u5FC3\uFF0C\u4F7F\u6211\u5011\u770B\u898B\u4E0A\u5E1D\u7684\u69AE\u8000<br> \u795E\u5728\u4EBA\u7684\u570B\u4E2D\u638C\u6B0A\uFF0C\u8981\u5C07\u570B\u8CDC\u8207\u8AB0\u5C31\u8CDC\u8207\u8AB0\uFF0C\u6216\u7ACB\u6975\u5351\u5FAE\u7684\u4EBA\u638C\u6B0A<br> \u4E0A\u5E1D\u6709\u5176\u505A\u4E8B\u6CD5\u5247\uFF0C\u795E\u9858\u610F\u4F7F\u7528\u53CA\u5351\u5FAE\u3001\u9858\u610F\u7684\u4EBA<br> \u8981\u8B39\u614E\u8A00\u884C\uFF0C\u907F\u514D\u904E\u65BC\u72C2\u50B2\uFF0C\u53CD\u800C\u8B93\u81EA\u5DF1\u5927\u904E\u4E0A\u5E1D<br> \u795E\u6A02\u610F\u8207\u8B19\u5351\u4EBA\u540C\u884C\uFF0C\u795E\u4E5F\u6703\u7528\u4E00\u6BB5\u7D93\u6B77\u8B93\u795E\u6210\u9577<br> \u5C3C\u5E03\u7532\u5C3C\u6492\u738B\u7D93\u6B77\u9019\u6BB5\u7CBE\u795E\u75BE\u75C5\u5F8C\uFF0C\u4E5F\u9AD4\u8A8D\u5230\u795E\u7684\u6CD5\u5247<br> \u6700\u5F8C\u4FEF\u9996\u8B19\u5351\u5730\u8AAA\u51FA\u8B9A\u7F8E\u795E\u7684\u8A71\uFF0C\u4E5F\u9858\u610F\u964D\u5351\u8B93\u795E\u4F86\u638C\u6B0A<br><span style="color:red;"> \u56E0\u70BA\u4ED6\u6240\u505A\u7684\u5168\u90FD\u8AA0\u5BE6\uFF0C\u4ED6\u6240\u884C\u7684\u4E5F\u90FD\u516C\u5E73<br> \u90A3\u884C\u52D5\u9A55\u50B2\u7684\uFF0C\u4ED6\u80FD\u964D\u70BA\u5351(V37)<br></span></p><p><img src="https://farm2.staticflickr.com/1721/42521257052_56e929f2d8_h.jpg" alt=""></p>',7),a=[p];function i(o,s,c,l,n,d){return b(),t("div",null,a)}var h=r(e,[["render",i]]);export{m as __pageData,h as default};
